"""
HealthLens AI — Agent 2: Plain-language Summary + Chat
Turns structured extraction into detailed, human-friendly explanations.
"""

import os
import json
import re
import logging
from groq import Groq
from models import (
    ExtractionResult, ComparisonResult, RecommendationResult,
    InsightCard, SpecialistRecommendation, TestStatus
)

logger = logging.getLogger(__name__)

DISCLAIMER = (
    "⚕️ This analysis is generated by AI for informational purposes only. "
    "It is NOT a medical diagnosis. Always consult a qualified doctor before making any health decisions."
)

